# ── Constants ─────────────────────────────────────────────────────────────────

KWIN_SERVICE     = "org.kde.KWin"
SCRIPTING_PATH   = "/Scripting"
RECEIVER_SERVICE = "org.probe.KWinTileTest"
RECEIVER_PATH    = "/Receiver"
RECEIVER_IFACE   = "org.probe.KWinTileTest"


# ── Colours ───────────────────────────────────────────────────────────────────

class C:
    _t     = sys.stdout.isatty()
    BOLD   = "\033[1m"  if _t else ""
    CYAN   = "\033[36m" if _t else ""
    GREEN  = "\033[32m" if _t else ""
    YELLOW = "\033[33m" if _t else ""
    RED    = "\033[31m" if _t else ""
    RESET  = "\033[0m"  if _t else ""

def info(m):  print(f"{C.CYAN}[INFO ] {C.RESET}{m}")
def ok(m):    print(f"{C.GREEN}[OK   ] {C.RESET}{m}")
def warn(m):  print(f"{C.YELLOW}[WARN ] {C.RESET}{m}")
def error(m): print(f"{C.RED}[ERROR] {C.RESET}{m}", file=sys.stderr)
def head(m):  print(f"\n{C.BOLD}{C.CYAN}{m}{C.RESET}")
def rline(label, value, good=True):
    mark = f"{C.GREEN}✓{C.RESET}" if good else f"{C.RED}✗{C.RESET}"
    print(f"  {mark}  {label:<45} {value}")


# ── D-Bus receiver ────────────────────────────────────────────────────────────

RECEIVER_XML = f"""
<node>
  <interface name='{RECEIVER_IFACE}'>
    <method name='receiveResult'>
      <arg type='s' name='test_name' direction='in'/>
      <arg type='s' name='json_data' direction='in'/>
    </method>
  </interface>
</node>
"""


class TileTestReceiver:
    dbus = RECEIVER_XML

    def __init__(self) -> None:
        self._results: dict[str, object] = {}
        self._events:  dict[str, threading.Event] = {}
        self._lock = threading.Lock()

    def expect(self, test_name: str) -> threading.Event:
        ev = threading.Event()
        with self._lock:
            self._events[test_name] = ev
        return ev

    def receiveResult(self, test_name: str, json_data: str) -> None:
        try:
            data = json.loads(json_data)
        except Exception as exc:
            data = {"parseError": str(exc), "raw": json_data[:200]}
        with self._lock:
            self._results[test_name] = data
            ev = self._events.get(test_name)
        if ev:
            ev.set()

    def get(self, test_name: str) -> object:
        with self._lock:
            return self._results.get(test_name)


# ── Script runner ─────────────────────────────────────────────────────────────

class ScriptRunner:
    def __init__(self, scripting, receiver: TileTestReceiver) -> None:
        self.scripting = scripting
        self.receiver  = receiver

    def run(self, test_name: str, js_body: str, timeout: float = 8.0) -> dict:
        svc   = RECEIVER_SERVICE
        path  = RECEIVER_PATH
        iface = RECEIVER_IFACE

        js = f"""
// KWin tile test — {test_name}
var _svc   = "{svc}";
var _path  = "{path}";
var _iface = "{iface}";
var _name  = "{test_name}";

function send(data) {{
    callDBus(_svc, _path, _iface, "receiveResult", _name,
             JSON.stringify(data));
}}

try {{
    {js_body}
}} catch(e) {{
    send({{ fatalError: String(e) }});
}}
"""
        js_fd, js_path = tempfile.mkstemp(
            suffix=".js", prefix=f"kwin_tile_{test_name}_"
        )
        os.close(js_fd)
        script_id = None
        ev = self.receiver.expect(test_name)

        try:
            with open(js_path, "w") as f:
                f.write(js)
            script_id = self.scripting.loadScript(js_path)
            self.scripting.start()
        except Exception as exc:
            os.unlink(js_path)
            return {"loadError": str(exc)}

        ev.wait(timeout=timeout)

        try:
            if script_id is not None:
                self.scripting.unloadScript(str(script_id))
        except Exception:
            pass
        try:
            os.unlink(js_path)
        except OSError:
            pass

        result = self.receiver.get(test_name)
        if result is None:
            return {"timeout": True, "test": test_name}
        return result


# ── Geometry helper ───────────────────────────────────────────────────────────

def geom_str(g: dict) -> str:
    if not g:
        return "(none)"
    return f"{g.get('x')},{g.get('y')}  {g.get('width')}x{g.get('height')}"


# ── Tests ─────────────────────────────────────────────────────────────────────

def test_introspect_slots(runner: ScriptRunner) -> list[str]:
    """
    Test A — introspect workspace for tiling slot methods.

    Iterates all properties of the workspace object and returns those whose
    names contain 'tile' or 'quicktile' (case-insensitive).  This tells us
    the exact names available in this KWin version without guessing.
    """
    head("Test A — Introspect workspace for tiling slot methods")

    result = runner.run("introspect_slots", """
var slots = [];
for (var key in workspace) {
    var kl = key.toLowerCase();
    if (kl.indexOf("tile") !== -1 || kl.indexOf("quicktile") !== -1) {
        slots.push({ name: key, type: typeof workspace[key] });
    }
}
// Also check a few specific names explicitly in case enumeration misses them
var candidates = [
    "slotWindowQuickTileLeft",
    "slotWindowQuickTileRight",
    "slotWindowQuickTileTop",
    "slotWindowQuickTileBottom",
    "slotWindowQuickTileTopLeft",
    "slotWindowQuickTileTopRight",
    "slotWindowQuickTileBottomLeft",
    "slotWindowQuickTileBottomRight",
];
var explicit = [];
for (var i = 0; i < candidates.length; i++) {
    explicit.push({
        name:   candidates[i],
        type:   typeof workspace[candidates[i]],
        exists: typeof workspace[candidates[i]] === "function",
    });
}
send({ slots: slots, explicit: explicit });
""")

    if "fatalError" in result:
        error(f"Test A failed: {result['fatalError']}")
        return []
    if "timeout" in result:
        error("Test A timed out")
        return []

    # Print enumerated slots (may be empty if workspace doesn't expose its keys)
    slots = result.get("slots", [])
    if slots:
        info(f"Enumerated {len(slots)} tile-related slot(s) on workspace:")
        for s in slots:
            info(f"  {s['name']}  (type: {s['type']})")
    else:
        info("No tile slots found via enumeration (workspace may not be enumerable)")

    # Print explicit probe results
    explicit = result.get("explicit", [])
    head("  Explicit slot name probe:")
    available = []
    for e in explicit:
        exists = e.get("exists", False)
        rline(e["name"], e["type"], good=exists)
        if exists:
            available.append(e["name"])

    if available:
        ok(f"\n  Available slot methods: {available}")
    else:
        warn("\n  No tiling slot methods found under the expected names.")
        warn("  Check KWin source or use kwin_introspect.py for alternate names.")

    return available


def test_tile_left(runner: ScriptRunner, target_id: str,
                   slot_name: str) -> dict:
    """
    Test B — tile the target window left using the confirmed slot method.

    Sets the window as activeWindow (required for slot methods), calls the
    slot, waits 500ms, and reads back geometry and screen name.
    """
    head(f"Test B — Tile left  (slot: {slot_name})")

    result = runner.run("tile_left", f"""
var bare  = "{target_id}";
var wins  = workspace.windowList();
var w     = null;
for (var i = 0; i < wins.length; i++) {{
    if (String(wins[i].internalId).replace(/[{{}}]/g,"") === bare) {{
        w = wins[i]; break;
    }}
}}
if (!w) {{
    send({{ error: "window not found", uuid: bare }});
}} else {{
    // Record geometry before tile
    var before = {{
        x: Number(w.frameGeometry.x),     y: Number(w.frameGeometry.y),
        width: Number(w.frameGeometry.width), height: Number(w.frameGeometry.height),
        screen: String(w.output ? w.output.name : ""),
    }};

    // Slot methods operate on the active window
    workspace.activeWindow = w;
    var pause = Date.now(); while(Date.now()-pause < 100) {{}}

    // Call the tiling slot
    workspace["{slot_name}"]();
    var pause2 = Date.now(); while(Date.now()-pause2 < 500) {{}}

    // Read geometry after tile
    var after = {{
        x: Number(w.frameGeometry.x),     y: Number(w.frameGeometry.y),
        width: Number(w.frameGeometry.width), height: Number(w.frameGeometry.height),
        screen: String(w.output ? w.output.name : ""),
    }};

    send({{ ok: true, before: before, after: after }});
}}
""")

    if "fatalError" in result:
        error(f"Test B failed: {result['fatalError']}")
        return {}
    if "timeout" in result:
        error("Test B timed out")
        return {}
    if "error" in result:
        error(f"Test B: {result['error']}")
        return {}

    before = result.get("before", {})
    after  = result.get("after",  {})
    info(f"  Before : {geom_str(before)}  screen={before.get('screen')}")
    info(f"  After  : {geom_str(after)}   screen={after.get('screen')}")

    changed = before != after
    if changed:
        ok("  Geometry changed — tile-left fired successfully")
    else:
        warn("  Geometry unchanged — slot may have had no effect")

    return after


