    if "timeout" in result2:
        error("Test I step 2 timed out"); return
    if "error" in result2:
        error(f"Test I step 2: {result2['error']}"); return

    info(f"  After step 2 (setMax(T,T)): "
         f"{result2.get('x')},{result2.get('y')}  "
         f"{result2.get('width')}x{result2.get('height')}"
         f"  maximized={result2.get('maximized')}"
         f"  tile={result2.get('tile')}")

    if result2.get("maximized"):
        ok("  SUCCESS -- confirmed working sequence:")
