def test_introspect_screen_move(runner: ScriptRunner) -> None:
    """
    Test N -- enumerate all workspace methods related to moving windows
    between screens, and check whether sendClientToScreen() is callable.

    Also probes the window object for any screen/output-related methods
    that might allow direct screen assignment without geometry tricks.
    """
    head("Test N -- Introspect screen-move methods on workspace and window")

    result = runner.run("introspect_screen_move", f"""
// --- Workspace-level screen move methods ---
var wsFound = [];
var wsKeywords = ["screen", "output", "monitor", "display"];
for (var key in workspace) {{
    var kl = key.toLowerCase();
    for (var k = 0; k < wsKeywords.length; k++) {{
        if (kl.indexOf(wsKeywords[k]) !== -1) {{
            wsFound.push({{ name: key, type: typeof workspace[key] }});
            break;
        }}
    }}
}}

// Explicit workspace candidates
var wsCandidates = [
    "sendClientToScreen",
    "sendWindowToScreen",
    "slotWindowToNextScreen",
    "slotWindowToPrevScreen",
    "slotWindowToAboveScreen",
    "slotWindowToBelowScreen",
    "slotWindowToLeftScreen",
    "slotWindowToRightScreen",
    "slotSwitchToNextScreen",
    "slotSwitchToPrevScreen",
    "slotSwitchToLeftScreen",
    "slotSwitchToRightScreen",
    "slotSwitchToAboveScreen",
    "slotSwitchToBelowScreen",
    "activeOutput",
    "activeScreen",
    "screens",
    "outputs",
];
var wsExplicit = [];
for (var i = 0; i < wsCandidates.length; i++) {{
    var key = wsCandidates[i];
    var t   = typeof workspace[key];
    var v   = "";
    try {{
        if (t !== "function") {{ v = String(workspace[key]).slice(0, 80); }}
    }} catch(e) {{ v = "(error)"; }}
    wsExplicit.push({{ name: key, type: t, value: v, exists: t !== "undefined" }});
}}

// --- Window-level screen/output methods ---
// Use the active window for window-object introspection
var w = workspace.activeWindow;
var winFound = [];
var winExplicit = [];
if (w) {{
    for (var key in w) {{
        var kl = key.toLowerCase();
        for (var k = 0; k < wsKeywords.length; k++) {{
            if (kl.indexOf(wsKeywords[k]) !== -1) {{
                var t = typeof w[key];
                var v = "";
                try {{
                    if (t !== "function") {{ v = String(w[key]).slice(0,60); }}
                }} catch(e) {{ v = "(error)"; }}
                winFound.push({{ name: key, type: t, value: v }});
                break;
            }}
        }}
    }}

    var winCandidates = [
        "output", "screen", "sendToOutput", "sendToScreen",
        "setOutput", "setScreen", "moveToOutput", "moveToScreen",
        "outputChanged",
    ];
    for (var i = 0; i < winCandidates.length; i++) {{
        var key = winCandidates[i];
        var t   = typeof w[key];
        var v   = "";
        try {{
            if (t !== "function") {{ v = String(w[key]).slice(0,60); }}
        }} catch(e) {{ v = "(error)"; }}
        winExplicit.push({{ name: key, type: t, value: v,
                            exists: t !== "undefined" }});
    }}
}}

// --- Try calling sendClientToScreen to see if it accepts arguments ---
var sendClientTest = {{ tried: false, error: "" }};
if (typeof workspace.sendClientToScreen === "function" && w) {{
    sendClientTest.tried = true;
    try {{
        // Just call with current screen to test the signature — no actual move
        workspace.sendClientToScreen(w, w.output);
        sendClientTest.result = "called without error";
    }} catch(e) {{
        sendClientTest.error = String(e);
    }}
}}

send({{
    ok:          true,
    wsFound:     wsFound,
    wsExplicit:  wsExplicit,
    winFound:    winFound,
    winExplicit: winExplicit,
    sendClientTest: sendClientTest,
    hasActiveWindow: Boolean(w),
}});
""", timeout=10.0)

    if "fatalError" in result:
        error(f"Test N failed: {result['fatalError']}"); return
    if "timeout"    in result:
        error("Test N timed out"); return
    if "error"      in result:
        error(f"Test N: {result['error']}"); return

    # Workspace enumerated screen-related properties
    ws_found = result.get("wsFound", [])
    if ws_found:
        info(f"Workspace screen-related properties ({len(ws_found)} found):")
        for p in sorted(ws_found, key=lambda x: x["name"]):
            val = f" = {p['value']!r}" if p.get("value") else ""
            info(f"  {p['name']:<45} ({p['type']}){val}")
    else:
        warn("No screen-related workspace properties found via enumeration")

    # Workspace explicit probes
    head("  Workspace explicit probe:")
    for p in result.get("wsExplicit", []):
        val = f"  [{p['value']}]" if p.get("value") else ""
        rline(p["name"], f"{p['type']}{val}", good=p.get("exists", False))

    # Window enumerated screen-related properties
    win_found = result.get("winFound", [])
    if not result.get("hasActiveWindow"):
        warn("No active window — window-level introspection skipped")
    elif win_found:
        head("  Window screen-related properties:")
        for p in sorted(win_found, key=lambda x: x["name"]):
            val = f" = {p['value']!r}" if p.get("value") else ""
            info(f"  {p['name']:<45} ({p['type']}){val}")
    else:
        warn("No screen-related properties found on window object")

    # Window explicit probes
    head("  Window explicit probe:")
    for p in result.get("winExplicit", []):
        val = f"  [{p['value']}]" if p.get("value") else ""
        rline(p["name"], f"{p['type']}{val}", good=p.get("exists", False))

    # sendClientToScreen call test
    sc = result.get("sendClientTest", {})
    head("  sendClientToScreen call test:")
    if sc.get("tried"):
        if sc.get("error"):
            warn(f"  Called but threw: {sc['error']}")
        else:
            ok(f"  {sc.get('result', 'called')}")
    else:
        info("  Not tried (function not present or no active window)")


def get_original_geometry(runner: ScriptRunner, target_id: str) -> dict:
    """Read the window's current geometry before any test modifies it."""
    result = runner.run("get_geom", f"""
var bare  = "{target_id}";
var wins  = workspace.windowList();
var w     = null;
for (var i = 0; i < wins.length; i++) {{
    if (String(wins[i].internalId).replace(/[{{}}]/g,"") === bare) {{
        w = wins[i]; break;
    }}
}}
if (!w) {{
    send({{ error: "window not found" }});
}} else {{
    send({{
        x:         Number(w.frameGeometry.x),
        y:         Number(w.frameGeometry.y),
        width:     Number(w.frameGeometry.width),
        height:    Number(w.frameGeometry.height),
        screen:    String(w.output ? w.output.name : ""),
        maximized: Boolean(w.maximized),
    }});
}}
""")
    return result


def test_restore(runner: ScriptRunner, target_id: str,
                 original: dict) -> None:
    """
    Test D -- restore the window to its original geometry and maximize state.
    """
    head("Test D -- Restore original geometry")

    if not original:
        warn("  No original geometry recorded -- skipping restore")
        return

    x       = original.get("x", 0)
    y       = original.get("y", 0)
    w       = original.get("width", 800)
    h       = original.get("height", 600)
    was_max = original.get("maximized", False)
    do_max  = "true" if was_max else "false"

    result = runner.run("restore", f"""
var bare  = "{target_id}";
var wins  = workspace.windowList();
var win   = null;
for (var i = 0; i < wins.length; i++) {{
    if (String(wins[i].internalId).replace(/[{{}}]/g,"") === bare) {{
        win = wins[i]; break;
    }}
}}
if (!win) {{
    send({{ error: "window not found" }});
}} else {{
    // Clear tile mode and unmaximize first so the window can be repositioned
    win.setMaximize(false, false);
    var p1 = Date.now(); while(Date.now()-p1 < 300) {{}}
    win.frameGeometry = {{ x: {x}, y: {y}, width: {w}, height: {h} }};
    var p2 = Date.now(); while(Date.now()-p2 < 300) {{}}
    if ({do_max}) {{
        win.setMaximize(true, true);
        var p3 = Date.now(); while(Date.now()-p3 < 400) {{}}
    }}
    send({{ ok: true, maximized: Boolean(win.maximized),
            x: Number(win.frameGeometry.x),
            y: Number(win.frameGeometry.y) }});
}}
""")

    if result.get("ok"):
        state = "maximized" if result.get("maximized") else f"{x},{y}  {w}x{h}"
        ok(f"  Restored [{state}]")
    else:
        warn(f"  Restore may have failed: {result}")


def test_window_tile_properties(runner: ScriptRunner, target_id: str,
                                tile_left_slot: str) -> None:
    """
    Test E — enumerate tile-related properties on the window object itself.

    Tiles the window left (to put it into KWin's quick-tile mode), then
    inspects all properties/methods on the window object whose names contain
    'tile', 'quick', or 'mode'.  This tells us whether there is a scriptable
    way to clear the tile mode flag — the equivalent of clicking the restore
    button — so that setMaximize() works normally afterward.
    """
    head("Test E — Window tile-mode properties (post-tile introspection)")

    result = runner.run("window_tile_props", f"""
var bare  = "{target_id}";
var wins  = workspace.windowList();
var w     = null;
for (var i = 0; i < wins.length; i++) {{
    if (String(wins[i].internalId).replace(/[{{}}]/g,"") === bare) {{
        w = wins[i]; break;
    }}
}}
if (!w) {{
    send({{ error: "window not found" }});
}} else {{
    // Record geometry before tile
    var before = {{
        x: Number(w.frameGeometry.x), y: Number(w.frameGeometry.y),
        width: Number(w.frameGeometry.width), height: Number(w.frameGeometry.height),
    }};

    // Put window into quick-tile mode
    workspace.activeWindow = w;
    var p1 = Date.now(); while(Date.now()-p1 < 100) {{}}
    workspace["{tile_left_slot}"]();
    var p2 = Date.now(); while(Date.now()-p2 < 800) {{}}

    // Now enumerate all window properties containing tile/quick/mode
    var found = [];
    for (var key in w) {{
        var kl = key.toLowerCase();
        if (kl.indexOf("tile")  !== -1 ||
            kl.indexOf("quick") !== -1 ||
            kl.indexOf("mode")  !== -1) {{
            var t = typeof w[key];
            var v = "";
            try {{
                if (t !== "function") {{
                    v = String(w[key]);
                }}
            }} catch(e) {{ v = "(error reading)"; }}
            found.push({{ name: key, type: t, value: v }});
        }}
    }}

    // Also probe specific candidates explicitly
    var candidates = [
        "quickTileMode",
        "setQuickTileMode",
        "tile",
        "tiled",
        "tilingMode",
        "clearQuickTile",
        "resetTile",
        "isTiled",
        "quickTile",
    ];
    var explicit = [];
    for (var i = 0; i < candidates.length; i++) {{
        var key = candidates[i];
        var t   = typeof w[key];
        var v   = "";
        try {{
            if (t !== "function") {{ v = String(w[key]); }}
        }} catch(e) {{ v = "(error reading)"; }}
        explicit.push({{ name: key, type: t, value: v,
                         exists: t !== "undefined" }});
    }}

    // Try calling setMaximize while in tile mode — does it work?
    var maxBefore = Boolean(w.maximized);
    var maxError  = "";
    try {{
        w.setMaximize(true, true);
        var p3 = Date.now(); while(Date.now()-p3 < 400) {{}}
    }} catch(e) {{
        maxError = String(e);
    }}
    var maxAfter = Boolean(w.maximized);

    send({{
        ok:         true,
        before:     before,
        found:      found,
        explicit:   explicit,
        maxBefore:  maxBefore,
        maxAfter:   maxAfter,
        maxError:   maxError,
    }});
}}
""", timeout=12.0)

    if "fatalError" in result:
        error(f"Test E failed: {result['fatalError']}")
        return
    if "timeout" in result:
        error("Test E timed out")
        return
    if "error" in result:
        error(f"Test E: {result['error']}")
        return

    # Enumerated tile-related properties
    found = result.get("found", [])
    if found:
        info(f"Tile/quick/mode properties on window object ({len(found)} found):")
        for p in found:
            val = f" = {p['value']!r}" if p["value"] else ""
            info(f"  {p['name']}  (type: {p['type']}){val}")
    else:
        warn("No tile/quick/mode properties found via enumeration")

    # Explicit probes
    head("  Explicit property probe:")
    for p in result.get("explicit", []):
        exists = p.get("exists", False)
        val = f" = {p['value']!r}" if p["value"] and p["type"] != "function" else ""
        rline(p["name"], f"{p['type']}{val}", good=exists)

    # setMaximize while in tile mode
    head("  setMaximize(true,true) while in tile mode:")
    max_before = result.get("maxBefore", False)
    max_after  = result.get("maxAfter",  False)
    max_error  = result.get("maxError",  "")
    info(f"  maximized before call : {max_before}")
    info(f"  maximized after call  : {max_after}")
    if max_error:
        warn(f"  setMaximize threw     : {max_error}")
    if max_after:
        ok("  setMaximize worked while in tile mode")
    else:
        warn("  setMaximize had no effect while in tile mode — tile mode blocks it")
    """Read the window's current geometry before any test modifies it."""
    result = runner.run("get_geom", f"""
var bare  = "{target_id}";
var wins  = workspace.windowList();
var w     = null;
for (var i = 0; i < wins.length; i++) {{
    if (String(wins[i].internalId).replace(/[{{}}]/g,"") === bare) {{
        w = wins[i]; break;
    }}
}}
if (!w) {{
    send({{ error: "window not found" }});
}} else {{
    send({{
        x:      Number(w.frameGeometry.x),
        y:      Number(w.frameGeometry.y),
        width:  Number(w.frameGeometry.width),
        height: Number(w.frameGeometry.height),
        screen: String(w.output ? w.output.name : ""),
        maximized: Boolean(w.maximized),
    }});
}}
""")
    return result


# ── Main ──────────────────────────────────────────────────────────────────────

def main() -> None:
    parser = argparse.ArgumentParser(
        prog="kwin_tile_test.py",
        description=(
            "Test KWin tiling slot methods.\n"
            "Get a window internalId first with: "
            "python3 kwin_probe.py --class <rc> -- <command>"
        ),
    )
    parser.add_argument("--id", required=True, metavar="UUID",
        help="internalId of a live window (without braces)")
    parser.add_argument("--disable-teste", action="store_true",
        help="Skip Test E (window tile-mode property introspection)")
    parser.add_argument("--disable-testf", action="store_true",
        help="Skip Test F (w.tile = null then maximize)")
    parser.add_argument("--disable-testg", action="store_true",
        help="Skip Test G (setMax(false,false) then maximize)")
    parser.add_argument("--disable-testh", action="store_true",
        help="Skip Test H (double setMax — known to hang KWin)")
    parser.add_argument("--disable-testi", action="store_true",
        help="Skip Test I (two-script safe sequence)")
    parser.add_argument("--disable-testj", action="store_true",
        help="Skip Test J (minimize then maximize)")
    parser.add_argument("--disable-testk", action="store_true",
        help="Skip Test K (workspace.slotWindowMaximize after tile-left)")
    parser.add_argument("--disable-testl", action="store_true",
        help="Skip Test L (introspect workspace for maximize slot names)")
    parser.add_argument("--disable-testm", action="store_true",
        help="Skip Test M (slotWindowMaximizeHorizontal + Vertical after tile-left)")
    parser.add_argument("--disable-testn", action="store_true",
        help="Skip Test N (introspect screen-move methods)")
    args = parser.parse_args()

    target_id = args.id.strip("{}")

    head("═══ KWin Tiling Slot Test ═══════════════════════════════════════")
    info(f"Target window : {target_id}")

    # ── Connect to D-Bus ──────────────────────────────────────────────────────
    bus = SessionBus()
    try:
        scripting = bus.get(KWIN_SERVICE, SCRIPTING_PATH)
    except Exception as exc:
        error(f"Cannot connect to KWin scripting interface: {exc}")
        sys.exit(1)

    receiver = TileTestReceiver()
    try:
        registration = bus.publish(RECEIVER_SERVICE, (RECEIVER_PATH, receiver))
    except Exception as exc:
        error(f"Cannot publish D-Bus receiver: {exc}")
        sys.exit(1)

    # Run GLib loop in a daemon thread for D-Bus callbacks
    loop = GLib.MainLoop()
    t = threading.Thread(target=loop.run, daemon=True)
    t.start()
    # Allow the GLib event loop to start processing before the first script fires
    time.sleep(1.0)

    runner = ScriptRunner(scripting, receiver)

    # ── Read original geometry before any modification ────────────────────────
    original = get_original_geometry(runner, target_id)
    info(f"[DIAG] get_original_geometry raw result: {original}")
    if "error" in original or "timeout" in original:
        error(f"Cannot find window {target_id!r} — is it still open?")
        error("Get a fresh internalId with: python3 kwin_probe.py --class <rc> -- <cmd>")
        loop.quit()
        sys.exit(1)

    info(f"Original geometry : {geom_str(original)}  "
         f"screen={original.get('screen')}  "
         f"maximized={original.get('maximized')}")

    # ── Test A: discover available slot names ─────────────────────────────────
    available_slots = test_introspect_slots(runner)

    # Determine which left-tile slot to use for tests B and C
    # Prefer the most commonly documented name; fall back if absent
    preferred = "slotWindowQuickTileLeft"
    if preferred in available_slots:
        tile_left_slot = preferred
    elif available_slots:
        # Use whatever left-tile slot was found
        lefts = [s for s in available_slots if "left" in s.lower()]
        tile_left_slot = lefts[0] if lefts else available_slots[0]
    else:
        warn("\nNo tiling slot methods confirmed available.")
        warn("Tests B, C, D skipped.  Check Test A output above.")
        warn("The slot names may differ in this KWin version.")
        loop.quit()
        sys.exit(0)

    # ── Test B: tile left ─────────────────────────────────────────────────────
    after_left = test_tile_left(runner, target_id, tile_left_slot)
    time.sleep(0.3)

    # ── Test C: tile right ────────────────────────────────────────────────────
    after_right = test_tile_right(runner, target_id, tile_left_slot)
    time.sleep(0.3)

    # ── Test E: window tile-mode properties ───────────────────────────────────
    if not args.disable_teste:
        test_window_tile_properties(runner, target_id, tile_left_slot)
        time.sleep(0.3)
    else:
        info("Test E skipped (--disable-teste)")

    # ── Test F: w.tile = null then maximize ───────────────────────────────────
    if not args.disable_testf:
        test_clear_tile_then_maximize(runner, target_id, tile_left_slot)
        time.sleep(0.3)
    else:
        info("Test F skipped (--disable-testf)")

    # ── Test G: setMaximize(false,false) to escape tile mode, then maximize ───
    if not args.disable_testg:
        test_unmaximize_then_maximize(runner, target_id, tile_left_slot)
        time.sleep(0.3)
    else:
        info("Test G skipped (--disable-testg)")

    # ── Test H: double setMaximize(true,true) — known to hang KWin ────────────
    if not args.disable_testh:
        test_double_maximize(runner, target_id, tile_left_slot)
        time.sleep(0.3)
    else:
        info("Test H skipped (--disable-testh)")

    # ── Test I: safe two-script tile-then-maximize sequence ───────────────────
    if not args.disable_testi:
        test_safe_tile_then_maximize(runner, target_id, tile_left_slot)
        time.sleep(0.3)
    else:
        info("Test I skipped (--disable-testi)")

    # ── Test J: minimize after tile-left, then maximize ───────────────────────
    if not args.disable_testj:
        test_minimize_then_maximize(runner, target_id, tile_left_slot)
        time.sleep(0.3)
    else:
        info("Test J skipped (--disable-testj)")

    # ── Test L: introspect workspace for maximize-related slot names ──────────
    max_slots: list[str] = []
    if not args.disable_testl:
        max_slots = test_introspect_maximize_slots(runner)
        time.sleep(0.3)
    else:
        info("Test L skipped (--disable-testl)")

    # ── Test K: workspace.slotWindowMaximize() after tile-left ────────────────
    # Use the first confirmed maximize slot from Test L, falling back to the
    # expected name if Test L was skipped or found nothing.
    max_slot = next(
        (s for s in max_slots if "maximize" in s.lower() and "horizontal" not in s.lower() and "vertical" not in s.lower()),
        "slotWindowMaximize"
    )
    if not args.disable_testk:
        test_slot_maximize(runner, target_id, tile_left_slot)
        time.sleep(0.3)
    else:
        info("Test K skipped (--disable-testk)")

    # ── Test M: slotWindowMaximizeHorizontal + Vertical after tile-left ───────
    if not args.disable_testm:
        test_slot_maximize_hv(runner, target_id, tile_left_slot)
        time.sleep(0.3)
    else:
        info("Test M skipped (--disable-testm)")

    # ── Test N: introspect screen-move methods ────────────────────────────────
    if not args.disable_testn:
        test_introspect_screen_move(runner)
        time.sleep(0.3)
    else:
        info("Test N skipped (--disable-testn)")

    # ── Test D: restore ───────────────────────────────────────────────────────
    test_restore(runner, target_id, original)

    # ── Summary ───────────────────────────────────────────────────────────────
    head("═══ Summary ═════════════════════════════════════════════════════")
    if available_slots:
        ok(f"Available tiling slots : {available_slots}")
    else:
        warn("No tiling slot methods found")

    info(f"Original geometry  : {geom_str(original)}")
    if after_left:
        info(f"After tile-left    : {geom_str(after_left)}")
    if after_right:
        info(f"After tile-right   : {geom_str(after_right)}")

    head("═══ Done ════════════════════════════════════════════════════════")
    loop.quit()


if __name__ == "__main__":
    main()
